```typescript
// ---- Scheduling Domain ----
export interface ApiSession {
  id: string;
  series_id?: string | null;
  course_id: string;
  room_id: string | null;
  teacher_id: string;
  start_at: string;    // RFC3339 UTC
  end_at: string;      // RFC3339 UTC
  version: number;
}

export interface ApiCourse {
  id: string;
  code: string;
  name: string;
  deleted_at?: string | null;
}

// The list response from /api/v1/courses includes additional fields
export interface ApiCourseRow {
  id: string;
  course_no: number;
  code: string;
  name: string;
  year: number | null;
  teacher_id: string | null;
  teacher_name: string;
  subject_id: string | null;
  subject_code: string;
  subject_name: string;
  hour: number | null;
  student_count: number | null;
  course_type: string | null;
  deleted_at?: string | null;
}

export interface ApiRoom {
  id: string;
  name: string;
  capacity: number | null;
}

export interface ApiUser {
  id: string;
  username: string;
  role: "Admin" | "Teacher";
}

export interface ApiStudent {
  id: string;
  wcode: string;
  full_name: string;
  notes: string;
  status?: string;
}

export interface ApiAttendanceOverride {
  student_id: string;
  status: "included" | "excluded";
  created_at: string;
}

// ---- Scheduling Conflict Types ----
export interface ApiConflictDetails {
  kind: string;
  requested: {
    start_at: string;
    end_at: string;
    course_id: string;
    room_id: string | null;
    teacher_id: string;
    series_id?: string | null;
  };
  conflicts: Array<{
    session_id: string;
    series_id?: string | null;
    course_id: string;
    room_id: string | null;
    teacher_id: string;
    start_at: string;
    end_at: string;
  }>;
  conflicting_students?: Array<{
    student_id: string;
    full_name: string;
    status: string;
  }>;
}

export interface ApiPreflightResponse {
  status: "available" | "provisional";
}

export interface ApiStaleEditDetails {
  current?: {
    id: string;
    course_id: string;
    room_id: string | null;
    teacher_id: string;
    weekdays: number[];
    start_local_time?: string;
    duration_minutes: number;
    start_date: string;
    end_date: string;
    count: number | null;
    version: number;
  };
}

export interface ApiSlotFinderSlot {
  date: string;
  start_time: string;
  end_time: string;
  status: "provisional" | "blocked";
  kind?: string;
  message?: string;
  conflicts?: Array<{
    session_id: string;
    series_id?: string | null;
    course_id: string;
    room_id: string | null;
    teacher_id: string;
    start_at: string;
    end_at: string;
  }>;
}

// ---- Availability Domain ----
export interface ApiAvailabilityWindow {
  id: string;
  start_at: string;
  end_at: string;
}

// ---- CRM Domain ----
export interface ApiCrmFilterResponse {
  enabled: boolean;
  locked: boolean;
  filter: unknown;
}

// ---- Auth Domain ----
export interface ApiCurrentUser {
  id: string;
  username: string;
  role: "Admin" | "Teacher";
}

// ---- API Common ----
